-- ---------------- Fire Knight's Castle (Stages 10-20) ----------------
insert into dungeons (name, has_wave_phase) values ('Fire Knight''s Castle', true) on conflict (name) do nothing;
insert into dungeon_stages (dungeon_id, stage_number, label, notes)
select d.id, s.num, s.lbl, s.note from dungeons d cross join (values
  (10, 'Stage 10', 'Spirit affinity. 10 hits to break shield — same as 15-20. Searing Storm active from this point.'),
  (11, 'Stage 11', 'Magic affinity. 10 hits to break shield.'),
  (12, 'Stage 12', 'Void affinity. 10 hits to break shield.'),
  (13, 'Stage 13', 'Force affinity. 10 hits to break shield.'),
  (14, 'Stage 14', 'Spirit affinity. 10 hits to break shield. Stat floors noticeably lower than stage 15+.'),
  (15, 'Stage 15', 'Magic affinity. 10 hits to break shield.'),
  (16, 'Stage 16', 'Void affinity. 10 hits to break shield.'),
  (17, 'Stage 17', 'Force affinity. 10 hits to break shield.'),
  (18, 'Stage 18', 'Spirit affinity. 10 hits to break shield.'),
  (19, 'Stage 19', 'Magic affinity. 10 hits to break shield.'),
  (20, 'Stage 20', 'Force affinity. 10 hits to break shield. Additional passives unlock at stage 20.')
) as s(num,lbl,note) where d.name='Fire Knight''s Castle' on conflict (dungeon_id,label) do nothing;
