insert into goal_solutions (goal_id, label, status, source_type, source_note, proposed_by)
select g.id, v.slabel, v.status, v.stype, v.snote, v.pby
from goals g join phases p on p.id=g.phase_id join dungeon_stages ds on ds.id=p.dungeon_stage_id join dungeons d on d.id=ds.dungeon_id
join (values
  ('Stage 10','wave','Clear the wave before dangerous minion skills activate — use AoE CC to deny their turns.','AoE Freeze','approved','human_observation','Freezes all wave enemies, denying their turns and preventing buff gains.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','wave','Clear the wave before dangerous minion skills activate — use AoE CC to deny their turns.','AoE Stun','approved','human_observation','Stuns all wave enemies, denying their turns entirely. Less critical than stage 15+ but still recommended for clean clears.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','wave','Clear the wave before dangerous minion skills activate — use AoE CC to deny their turns.','AoE Decrease Turn Meter','approved','human_observation','Pushes wave enemies'' turns back, buying time to clear them before any dangerous skills fire.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','boss','Counter Dazzling Flames SPD debuff — without an SPD buffer or Cleanse your team loses turns to the boss.','Increase SPD buff (team-wide)','approved','human_observation','A team-wide Increase SPD buff offsets Dazzling Flames so the team keeps its hit cadence.','fk-doc-gap-seed-2026-07-13'),
  ('Stage 10','boss','Counter Dazzling Flames SPD debuff — without an SPD buffer or Cleanse your team loses turns to the boss.','Cleanse (removes SPD debuff)','approved','human_observation','Removes the 30% Decrease SPD from Dazzling Flames (base skill, cooldown 5, active at every stage per the FK guide).','fk-doc-gap-seed-2026-07-13'),
  ('Stage 10','boss','Break the shield every round before Fyro takes his turn — same 10-hit requirement as stages 15-20, but enemy stats are lower so the gear bar is lower too.','Multi-Hit A1 champions (5 x 2+ hits = 10+)','approved','human_observation','Five champions each hitting 2+ times generates 10+ hits per round. At stage 10-14 this is achievable with budget multi-hitters since enemy DEF/HP is lower than stage 15+.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','boss','Break the shield every round before Fyro takes his turn — same 10-hit requirement as stages 15-20, but enemy stats are lower so the gear bar is lower too.','Multi-Hit A1 champions + Counterattack buff','approved','human_observation','A single Counterattack buff on a multi-hit champion adds meaningful extra hits — confirmed effective strategy even at lower stages (Jizoh example, free champion).','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','boss','Break the shield every round before Fyro takes his turn — same 10-hit requirement as stages 15-20, but enemy stats are lower so the gear bar is lower too.','Multi-Hit A1 champions + Increase Turn Meter','approved','human_observation','Increase Turn Meter grants the team extra turns = more attacks toward the shield each round. The FK guide lists a Speed champ with Increase Speed AND Increase Turn Meter as a core requirement. AND-combo: Turn Meter boost alone does not break a shield, so it pairs with multi-hit A1 champions.','fk-doc-gap-seed-2026-07-13'),
  ('Stage 10','boss','Break the shield every round before Fyro takes his turn — same 10-hit requirement as stages 15-20, but enemy stats are lower so the gear bar is lower too.','Multi-Hit A1 champions + Ally Attack','approved','human_observation','An unconditional team-wide Ally Attack adds a burst of hits toward the 10-hit shield. Added per advisor review 2026-07-13 to match Stages 7-9 and 15-20.','fk-approval-2026-07-13'),
  ('Stage 10','boss','Apply Decrease DEF and Weaken once shield is down to maximize damage in the window before it regenerates.','Decrease Turn Meter + Decrease SPD','approved','human_observation','Maximizes the post-shield damage window. Not strictly required at stage 10-14 the way it is at 15-20.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','boss','Apply Decrease DEF and Weaken once shield is down to maximize damage in the window before it regenerates.','Decrease DEF + Weaken','approved','human_observation','Wired 2026-07-12: coverage goal had no solution (Fire Knight boss damage window).',null),
  ('Stage 10','boss','Apply Decrease DEF and Weaken once shield is down to maximize damage in the window before it regenerates.','Decrease Turn Meter only','approved','human_observation','Often sufficient at stage 10-14 given lower enemy speed floor.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 10','boss','Deny Fyro''s per-turn self-heal — Cloak of Fire heals him at the start of every turn, scaling with shield strength, which can undo your shield-break damage.','Heal Reduction','approved','human_observation','Heal Reduction cuts Fyro''s per-turn self-heal (Cloak of Fire passive). STAGED informational — the advisor decides at approval whether to promote this to a hard coverage goal; leaving it informational avoids over-penalizing teams that win purely by breaking the shield every round.','fk-doc-gap-seed-2026-07-13'),
  ('Stage 10','boss','Control Fyro''s Turn Meter after the shield breaks — keep him in the vulnerable state as long as possible.','Decrease Turn Meter','approved','human_observation','Sufficient at stage 10-14 — Fyro''s lower base speed at this tier means TM reduction alone usually keeps him locked out without needing a separate SPD debuff.','fire-knight-ice-golem-10-14-seed-june-2026'),
  ('Stage 11','wave','Clear the wave before dangerous minion skills activate — use AoE CC to deny their turns.','AoE Freeze','approved','human_observation','Freezes all wave enemies, denying their turns and preventing buff gains.','fire-knight-ice-golem-10-14-seed-june-2026'),
