insert into boss_exceptions (dungeon_stage_id, description, source_citation)
select ds.id, v.descr, v.cite from dungeon_stages ds join dungeons d on d.id=ds.dungeon_id
join (values
  ('Stage 10','Spirit affinity stage. CONFIRMED: shield is 10 hits at this stage — same mechanic as stage 15-20, not a reduced version. Searing Storm (Max HP destroy AoE) is active from stage 7, so it is live here. The mechanic is identical to higher stages — the difference is enemy stat floors, not mechanic complexity. This is the stage where new players first encounter the full 10-hit shield requirement.','AyumiLove Fire Knight guide + empyreanrule.com (confirmed 2026)'),
  ('Stage 10','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
  ('Stage 11','Magic affinity stage. Same 10-hit shield mechanic.','AyumiLove Fire Knight guide + empyreanrule.com (confirmed 2026)'),
  ('Stage 11','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
  ('Stage 12','Void affinity stage — no affinity advantage or penalty for any champion.','AyumiLove Fire Knight guide + empyreanrule.com (confirmed 2026)'),
  ('Stage 12','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
  ('Stage 13','Force affinity stage. Same 10-hit shield mechanic.','AyumiLove Fire Knight guide + empyreanrule.com (confirmed 2026)'),
  ('Stage 13','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
  ('Stage 14','Spirit affinity stage. Last stage before the difficulty/stat jump that begins at stage 15. Good benchmark stage for testing whether a team is ready to push to 15+.','AyumiLove Fire Knight guide + empyreanrule.com (confirmed 2026)'),
  ('Stage 14','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
  ('Stage 15','Magic affinity stage (Force has advantage). 10-hit shield. Boss is immune to all debuffs while shield is active — do not waste debuff skills until shield breaks. Dazzling Flames (30% Decrease SPD AoE) activates every 5 turns.','AyumiLove Fire Knight guide + HellHades TM champions guide (2026)'),
  ('Stage 15','Almighty Immunity (passive): Fyro is immune to Stun, Freeze, Sleep, Provoke, Block Active Skills, Block Passive Skills, Fear and True Fear, plus HP-exchange, HP-balancing and cooldown-increase effects. Hard CC works only on the MINIONS, never on the boss — do not field a champion expecting to CC Fyro himself.','AyumiLove Fire Knight''s Castle guide (hand-read factual mechanics), 2026'),
