insert into stat_threshold_checks (phase_id, stat, comparison, formula, notes)
select p.id, v.stat, v.cmp, v.formula, v.note from phases p join dungeon_stages ds on ds.id=p.dungeon_stage_id join dungeons d on d.id=ds.dungeon_id
join (values
  ('Stage 10','boss','acc','formula','120','Stage 10-13: ACC 120+ is a reasonable starting floor. JUDGMENT CALL — lower than the 200+ used at stage 15-20 since the boss mechanics are confirmed forgiving at this range. Not confirmed from primary source numerically.'),
  ('Stage 10','boss','hp','formula','8000','Stage 10-13: HP 8000 floor — BATTLE-LOG DERIVED 2026-07-01 (was 25000, a dataless judgment call). DonCobb07 4W/1L Ice Golem 10 clear has team-min HP 9118 (Kael), so 25000 was a false negative. 8000 sits below the observed clearing minimum; refine with more data points.'),
  ('Stage 11','boss','hp','formula','8000','Stage 10-13: HP 8000 floor — BATTLE-LOG DERIVED 2026-07-01 (was 25000, a dataless judgment call). DonCobb07 4W/1L Ice Golem 10 clear has team-min HP 9118 (Kael), so 25000 was a false negative. 8000 sits below the observed clearing minimum; refine with more data points.'),
