  ('Stage 18','boss','hp','formula','40000','HP 40000+ recommended at stages 15-20. Frigid Vengeance with both minions alive ignores 100% DEF — survival depends entirely on HP when triggered in worst case. DEF alone is not sufficient. Stage 20 hp floor: 40k minimum, 50k+ recommended for comfortable auto-farming.'),
  ('Stage 19','boss','acc','formula','200','ICC Golem stages 15-20: ACC 200+ recommended to maintain reliable debuff landing even during Numbing Chill (50% Decrease ACC). If ACC is exactly at the minimum floor, Numbing Chill causes debuffs to fail 50%+ of the time. Build ACC with margin — 200+ at stage 20. Unconfirmed from primary source, treat as directional floor.'),
  ('Stage 19','boss','res','formula','200','RES 200+ recommended to resist Frigid Vengeance Freeze at stages 15-20. Freeze chance is 20% base + 40% per alive minion — with 1 alive minion it''s 60%, with 2 alive it''s 100%. RES 200+ gives meaningful resistance against the 60% case. Against 100% Freeze (both minions alive), higher RES (300+) is needed. Treat as directional floor — primary source confirmation needed.'),
  ('Stage 19','boss','hp','formula','40000','HP 40000+ recommended at stages 15-20. Frigid Vengeance with both minions alive ignores 100% DEF — survival depends entirely on HP when triggered in worst case. DEF alone is not sufficient. Stage 20 hp floor: 40k minimum, 50k+ recommended for comfortable auto-farming.'),
  ('Stage 20','boss','acc','formula','200','ICC Golem stages 15-20: ACC 200+ recommended to maintain reliable debuff landing even during Numbing Chill (50% Decrease ACC). If ACC is exactly at the minimum floor, Numbing Chill causes debuffs to fail 50%+ of the time. Build ACC with margin — 200+ at stage 20. Unconfirmed from primary source, treat as directional floor.'),
  ('Stage 20','boss','res','formula','200','RES 200+ recommended to resist Frigid Vengeance Freeze at stages 15-20. Freeze chance is 20% base + 40% per alive minion — with 1 alive minion it''s 60%, with 2 alive it''s 100%. RES 200+ gives meaningful resistance against the 60% case. Against 100% Freeze (both minions alive), higher RES (300+) is needed. Treat as directional floor — primary source confirmation needed.'),
  ('Stage 20','boss','hp','formula','40000','HP 40000+ recommended at stages 15-20. Frigid Vengeance with both minions alive ignores 100% DEF — survival depends entirely on HP when triggered in worst case. DEF alone is not sufficient. Stage 20 hp floor: 40k minimum, 50k+ recommended for comfortable auto-farming.')
) as v(lbl,ptype,stat,cmp,formula,note) on ds.label=v.lbl and p.phase_type=v.ptype
where d.name='Ice Golem''s Peak' and not exists (select 1 from stat_threshold_checks x where x.phase_id=p.id and x.stat=v.stat);
insert into boss_exceptions (dungeon_stage_id, description, source_citation)
select ds.id, v.descr, v.cite from dungeon_stages ds join dungeons d on d.id=ds.dungeon_id
join (values
  ('Stage 10','Magic affinity. Frigid Vengeance triggers at the same 5 HP thresholds as stage 15-20 (80/60/45/30/15%), but is confirmed forgiving here — players commonly clear by just attacking Klyssus directly without managing the mechanic. Counterattack is still a latent risk but rarely punishes at this stage. This is a good stage to introduce the mechanic to a new player without it being a hard requirement yet.','AyumiLove + empyreanrule.com + forum.plarium.com + raid-codex.com (confirmed 2026)'),
  ('Stage 11','Force affinity. Same forgiving Frigid Vengeance behavior as stage 10.','AyumiLove + empyreanrule.com + forum.plarium.com + raid-codex.com (confirmed 2026)'),
  ('Stage 12','Void affinity — no advantage or penalty. Same forgiving behavior.','AyumiLove + empyreanrule.com + forum.plarium.com + raid-codex.com (confirmed 2026)'),
  ('Stage 13','Spirit affinity. Same forgiving behavior. Last "easy" stage before the transition.','AyumiLove + empyreanrule.com + forum.plarium.com + raid-codex.com (confirmed 2026)'),
  ('Stage 14','Magic affinity. CONFIRMED TRANSITION STAGE — multiple independent sources state difficulty increases dramatically starting here. Teams that cleared stages 10-13 by ignoring Frigid Vengeance will start failing here if both minions are alive when a threshold triggers — DEF is bypassed entirely and Freeze chance approaches 100%. Treat this stage with the same rigor as stage 15-20: prioritize Poison/HP Burn over burst damage, manage minions actively, avoid Counterattack.','AyumiLove + empyreanrule.com + forum.plarium.com + raid-codex.com (confirmed 2026)'),
  ('Stage 15','Force affinity. Frigid Vengeance triggers at 5 HP thresholds: 80/60/45/30/15%. Each trigger revives dead minions and ignores 50% DEF per alive minion. With both minions alive: 100% DEF ignore + 100% Freeze chance (resistable). Poison/HP Burn damage does NOT trigger Frigid Vengeance. COUNTERATTACK IS DANGEROUS HERE — reflect damage off shields can proc Frigid Vengeance threshold attacks. Never use Counterattack buffs on Ice Golem.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)'),
  ('Stage 16','Void affinity — no affinity advantage or penalty. All Frigid Vengeance mechanics apply same as stage 15. Numbing Chill (50% Decrease ACC AoE, 4-turn cooldown) is the most disruptive non-damage mechanic.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)'),
  ('Stage 17','Spirit affinity. Frigid Vengeance same as stage 15-16. Magic champions have advantage here.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)'),
  ('Stage 18','Magic affinity. Frigid Vengeance same. Force champions have advantage here. Boss damage output increases at this tier.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)'),
  ('Stage 19','Force affinity. Frigid Vengeance same. Magic champions have advantage here.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)'),
  ('Stage 20','Spirit affinity. Primary farming stage for HP and Defense gear. Frigid Vengeance triggers at 5 HP thresholds. Frigid Vengeance ignores 50% DEF per alive minion — with both minions alive, DEF is completely bypassed and Freeze chance hits 100%. Poison/HP Burn bypasses ALL Frigid Vengeance triggers. Almighty Strength passive (stages 21-25) is NOT yet active at stage 20 — Max HP damage caps do not apply here. Counterattack buffs remain dangerous at this stage.','AyumiLove Ice Golem guide + empyreanrule.com + forum.plarium.com (confirmed 2026)')
) as v(lbl,descr,cite) on ds.label=v.lbl
where d.name='Ice Golem''s Peak' and not exists (select 1 from boss_exceptions x where x.dungeon_stage_id=ds.id and x.description=v.descr);
